// MinimockFinish checks that all mocked methods have been called the expected number of times
func (m *QueueMock) MinimockFinish() {
	m.finishOnce.Do(func() {
		if !m.minimockDone() {
			m.MinimockEnqueueJobInspect()

			m.MinimockGetJobInspect()

			m.MinimockSaveJobInspect()
		}
	})
}

// MinimockWait waits for all mocked methods to be called the expected number of times
func (m *QueueMock) MinimockWait(timeout mm_time.Duration) {
	timeoutCh := mm_time.After(timeout)
	for {
		if m.minimockDone() {
			return
		}
		select {
		case <-timeoutCh:
			m.MinimockFinish()
			return
		case <-mm_time.After(10 * mm_time.Millisecond):
		}
	}
}

func (m *QueueMock) minimockDone() bool {
	done := true
	return done &&
		m.MinimockEnqueueJobDone() &&
		m.MinimockGetJobDone() &&
		m.MinimockSaveJobDone()
}
